#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int freq[100001]; // enough for Ai up to 1e5, adjust if needed
        memset(freq,0,sizeof(freq));
        int maxFreq=0, x;
        for(int i=0;i<N;i++){
            scanf("%d",&x);
            if(x>=0 && x<100001) freq[x]++;
            else {
                // fallback for larger values using simple linear search (rare for given constraints)
                // not needed for official limits
            }
            if(freq[x]>maxFreq) maxFreq=freq[x];
        }
        printf("%d\n", N - maxFreq);
    }
    return 0;
}

